has_command() { command -v "$1" >/dev/null 2>&1; }
ensure_dir() { mkdir -p "$1"; }
copy_file() { [ -f "$1" ] && cp "$1" "$2"; }

sed_inplace() {
  local pattern="$1" replacement="$2" file="$3"
  if sed --version 2>/dev/null | grep -q GNU; then sed -i "s|${pattern}|${replacement}|g" "$file"
  else sed -i '' "s|${pattern}|${replacement}|g" "$file"; fi
}

safe_rmrf() {
  local target="$1" parent="$2"
  case "$target" in ""|"/"|"$HOME") _openllm_fail "refusing to remove $target" ;; esac
  case "/$target/" in *"/../"*) _openllm_fail "refusing path containing .." ;; esac
  case "$target" in "$parent"/*) ;; *) _openllm_fail "$target escapes $parent" ;; esac
  rm -rf "$target"
}

backup_once() {
  local src="$1" root="$HOME/.openllm/backups/$2" rel dest
  case "$src" in "$HOME"/*) rel="${src#"$HOME"/}" ;; *) rel="${src#/}" ;; esac
  dest="$root/$rel"
  [ ! -e "$dest" ] && [ ! -e "$dest.absent" ] || return 0
  (umask 077; mkdir -p "$(dirname "$dest")") 2>/dev/null || return 0
  if [ -f "$src" ]; then cp -p "$src" "$dest" 2>/dev/null && chmod 600 "$dest" 2>/dev/null || true
  else : > "$dest.absent" 2>/dev/null || true; fi
  chmod 700 "$HOME/.openllm/backups" "$root" 2>/dev/null || true
}

ensure_cli() {
  local display="$1" cmd="$2" dest_bin="$3" install_url="$4"
  if has_command "$cmd" || [ -x "$dest_bin" ]; then printf '  %s: already installed.\n' "$display"; return 0; fi
  if [ -n "${OPENLLM_SKIP_CLI_INSTALL:-}" ]; then
    printf '  %s: CLI not installed. Run its official installer first.\n' "$display" >&2
    return 1
  fi
  printf '  %s: installing the official CLI...\n' "$display"
  curl -fsSL "$install_url" | bash
  has_command "$cmd" || [ -x "$dest_bin" ] || _openllm_fail "$display install completed but its CLI was not found"
}

# ── Install state: ONE canonical file, ~/.openllm/state.json ────────────────
# Line-oriented JSON we fully own (only this runtime writes it): the opening
# and closing braces on their own lines and EXACTLY one entry per line —
#   "setup-<slug>": {"sha256":"…","version":"…","commit":"…"},
# so bash can update it with grep/sed alone (no jq/python3 dependency).
# Written IN PLACE (cat >), not tmp+rename: under the daemon's OS sandbox
# state.json is a FILE-scoped grant — a sibling tmp create + rename needs
# create-rights on the (ungranted) ~/.openllm dir. The next content is staged
# in $TMPDIR first and restored on a failed write, so a mid-write failure
# never truncates the record (same posture as the settings.json merges).
OPENLLM_STATE_FILE="$HOME/.openllm/state.json"

_openllm_state_entry_line() {
  grep -m1 "^\"setup-raycast\":" "$OPENLLM_STATE_FILE" 2>/dev/null || true
}

_openllm_state_field() {
  # $1 = field name; prints the entry's field value (empty when absent).
  _openllm_state_entry_line | sed -n "s/.*\"$1\":\"\([^\"]*\)\".*/\1/p"
}

_openllm_state_rewrite() {
  # $1 = replacement entry line ('' = delete). Rebuilds the file from the
  # surviving entry lines + the replacement, brace-wrapped. Best-effort: any
  # failure leaves the previous state intact and never fails the caller.
  local tmp orig
  tmp="$(mktemp "${TMPDIR:-/tmp}/openllm-state.XXXXXX" 2>/dev/null)" || return 0
  {
    printf '{\n'
    { grep '^"' "$OPENLLM_STATE_FILE" 2>/dev/null || true; } | grep -v "^\"setup-raycast\":" || true
    [ -n "$1" ] && printf '%s\n' "$1"
    printf '}\n'
  } > "$tmp" 2>/dev/null || { rm -f "$tmp" 2>/dev/null; return 0; }
  orig="$(mktemp "${TMPDIR:-/tmp}/openllm-state-orig.XXXXXX" 2>/dev/null)" || { rm -f "$tmp" 2>/dev/null; return 0; }
  cat "$OPENLLM_STATE_FILE" > "$orig" 2>/dev/null || true
  if ! { cat "$tmp" > "$OPENLLM_STATE_FILE"; } 2>/dev/null; then
    cat "$orig" > "$OPENLLM_STATE_FILE" 2>/dev/null || true
  fi
  chmod 600 "$OPENLLM_STATE_FILE" 2>/dev/null || true
  rm -f "$tmp" "$orig" 2>/dev/null || true
}

record_install_stamp() {
  # Piped installs export an empty digest (no file to self-hash) — skip the
  # stamp rather than writing a value drift comparison would misread.
  [[ "${OPENLLM_SELF_SHA256:-}" =~ ^[0-9a-f]{64}$ ]] || return 0
  (umask 077; mkdir -p "$HOME/.openllm") 2>/dev/null || return 0
  local commit=""
  [[ "${OPENLLM_REGISTRY_COMMIT:-}" =~ ^[0-9a-f]{40}$ ]] && commit="$OPENLLM_REGISTRY_COMMIT"
  _openllm_state_rewrite "\"setup-raycast\": {\"sha256\":\"$OPENLLM_SELF_SHA256\",\"version\":\"1.7.1-alpha.0\",\"commit\":\"$commit\",\"gateway\":\"${OPENLLM_GATEWAY_MODE:-}\"},"
  # Legacy per-file stamps superseded by state.json — clear so nothing stale
  # survives beside the canonical record.
  rm -f "$HOME/.openllm/installed/setup-raycast" \
    "$HOME/.openllm/installed/setup-raycast.version" \
    "$HOME/.openllm/installed/setup-raycast.commit" 2>/dev/null || true
  rmdir "$HOME/.openllm/installed" 2>/dev/null || true
}
clear_install_stamp() {
  _openllm_state_rewrite ""
  # Also clear legacy stamp files: the per-file installed/ era, tar-era route
  # prefixes ("setups-"/"plugins-"), and the pre-fold "plugin"-area name.
  rm -f "$HOME/.openllm/installed/setup-raycast" \
    "$HOME/.openllm/installed/setup-raycast.version" \
    "$HOME/.openllm/installed/setup-raycast.commit" \
    "$HOME/.openllm/installed/setups-raycast" \
    "$HOME/.openllm/installed/plugin-raycast" \
    "$HOME/.openllm/installed/plugins-raycast" 2>/dev/null || true
  rmdir "$HOME/.openllm/installed" 2>/dev/null || true
}
read_install_stamp() {
  local value
  value="$(_openllm_state_field sha256)"
  # Legacy fallback: the per-file installed/ era (pre-state.json installs).
  if [ -z "$value" ]; then
    local candidate
    for candidate in "setup-raycast" "setups-raycast" "plugin-raycast" "plugins-raycast"; do
      [ -f "$HOME/.openllm/installed/$candidate" ] || continue
      value="$(cat "$HOME/.openllm/installed/$candidate" 2>/dev/null || true)"
      break
    done
  fi
  [[ "$value" =~ ^[0-9a-f]{64}$ ]] && printf '%s' "$value"
  return 0
}
read_install_version() {
  local value
  value="$(_openllm_state_field version)"
  [ -n "$value" ] || value="$(cat "$HOME/.openllm/installed/setup-raycast.version" 2>/dev/null || true)"
  case "$value" in *[!0-9a-zA-Z.-]*|'') return 0 ;; esac
  printf '%s' "$value"
}
read_install_gateway() {
  # The gateway mode this item was INSTALLED with ("local"/"cloud"); empty
  # for stamps predating the field (pre-gateway-mode installs).
  local value
  value="$(_openllm_state_field gateway)"
  case "$value" in local|cloud) printf '%s' "$value" ;; esac
  return 0
}
emit_install_state() {
  # $1 = "true"/"false" (the script's own installed verdict). Prints the
  # complete `-s` state JSON line from the wrapper-owned stamp readers —
  # ONE format string, so the contract the daemon's parseState reads can't
  # drift per script.
  local version="null" gateway="null" iv igw
  iv="$(read_install_version)"
  [ -n "$iv" ] && version="\"$iv\""
  igw="$(read_install_gateway)"
  [ -n "$igw" ] && gateway="\"$igw\""
  printf '{"installed":%s,"version":%s,"installed_sha256":"%s","installed_commit":"%s","gateway":%s}\n' \
    "$1" "$version" "$(read_install_stamp)" "$(read_install_commit)" "$gateway"
}
read_install_commit() {
  local value
  value="$(_openllm_state_field commit)"
  [ -n "$value" ] || value="$(cat "$HOME/.openllm/installed/setup-raycast.commit" 2>/dev/null || true)"
  [[ "$value" =~ ^[0-9a-f]{40}$ ]] || return 0
  printf '%s' "$value"
}

OPENLLM_CLOUD_ORIGIN="${OPENLLM_CLOUD_ORIGIN:-}"
GATEWAY_ORIGIN="$OPENLLM_CLOUD_ORIGIN"
API_KEY="${OPENLLM_API_KEY:-}"
OPENLLM_REGISTRY_REQUIRES_KEY="1"

_openllm_prepare_mode() {
