  for arg in "$@"; do
    case "$arg" in
      -u) mode="uninstall" ;;
      -s) mode="state" ;;
    esac
  done
  if [ "$mode" = "install" ]; then
    [ -n "$OPENLLM_CLOUD_ORIGIN" ] || _openllm_fail "OPENLLM_CLOUD_ORIGIN is required"
    if [ "$OPENLLM_REGISTRY_REQUIRES_KEY" = "1" ]; then
      [ -n "$API_KEY" ] || _openllm_fail "OPENLLM_API_KEY is required"
    fi
  fi
}
# Install-time gateway mode (local | cloud, default local — "local first").
# Parsed and STRIPPED here so authored script bodies keep their strict
# usage loops; the value reaches them as OPENLLM_GATEWAY_MODE. A client
# setup bakes the daemon base URL under "local" and the cloud origin under
# "cloud"; the mode is stamped so the dashboard can prompt a reinstall
# when the user flips it. Only setups declaring `gateway_modes` accept the
# flag (compiled in as the capability gate below) — passing it to any
# other setup fails rather than stamping a meaningless mode.
OPENLLM_REGISTRY_GATEWAY_CAPABLE="1"
OPENLLM_GATEWAY_MODE="${OPENLLM_GATEWAY_MODE:-local}"
_openllm_gw_args=()
while [ $# -gt 0 ]; do
  case "$1" in
    --gateway|--gateway=*)
      [ "$OPENLLM_REGISTRY_GATEWAY_CAPABLE" = "1" ] || _openllm_fail "this setup does not take --gateway (no gateway_modes declared)"
      case "$1" in
        --gateway)
          shift
          [ $# -gt 0 ] || _openllm_fail "--gateway requires a value (local|cloud)"
          OPENLLM_GATEWAY_MODE="$1" ;;
        *)
          OPENLLM_GATEWAY_MODE="${1#--gateway=}" ;;
      esac
      shift ;;
    *)
      _openllm_gw_args+=("$1"); shift ;;
  esac
done
case "$OPENLLM_GATEWAY_MODE" in
  local|cloud) ;;
  *) _openllm_fail "invalid --gateway value (expected local or cloud)" ;;
esac
