set -- ${_openllm_gw_args[@]+"${_openllm_gw_args[@]}"}

# Resolve the base URL the setup bakes (gateway-capable setups, INSTALL
# runs only — a `-s`/`-u` run must not pay a network probe). ONE shared
# implementation so probe policy (port default, timeout, messages) can't
# drift across scripts. "local" probes the daemon's loopback /status for
# REACHABILITY only and falls back to the cloud origin with a warning;
# "cloud" always uses the origin. Exported for authored bodies.
OPENLLM_API_BASE="${OPENLLM_CLOUD_ORIGIN:-}"
_openllm_is_install=1
for _openllm_arg in "$@"; do
  case "$_openllm_arg" in -u|-s) _openllm_is_install=0 ;; esac
